1	import { readFileSync } from "node:fs";
2	import { quote, claim, type Item, type Incident } from "./claim-office.js";
3	
4	const INSURANCE_VALUES: Record<string, number> = {
5	  sword: 1000,
6	  amulet: 600,
7	  staff: 800,
8	  potion: 400,
9	  rune: 250,
10	  moonstone: 250,
11	};
12	
13	const { customer, steps } = JSON.parse(readFileSync(0, "utf-8"));
14	
15	type Step =
16	  | { op: "quote"; items: Item[] }
17	  | { op: "claim"; policy: number; incident: Incident };
18	
19	const quotePolicies: Item[][] = [];
20	const remainingCaps = new Map<number, number>();
21	
22	const results = (steps as Step[]).map((step) => {
23	  if (step.op === "quote") {
24	    quotePolicies.push(step.items);
25	    return { premium: quote(customer, step.items) };
26	  }
27	  const policyItems = quotePolicies[step.policy];
28	  if (!remainingCaps.has(step.policy)) {
29	    const cap = policyItems.reduce(
30	      (sum, item) => sum + 2 * INSURANCE_VALUES[item.type],
31	      0,
32	    );
33	    remainingCaps.set(step.policy, cap);
34	  }
35	  const remCap = remainingCaps.get(step.policy)!;
36	  const result = claim({ items: policyItems }, step.incident, remCap);
37	  remainingCaps.set(step.policy, result.remainingCap);
38	  return result;
39	});
